mapper.select:
select * from nx_community_dispatch_stop
where nx_cds_plan_id = #{planId}
  and nx_cds_stop_status != #{cancelledStatus}
order by nx_cds_route_seq

select count(*) from nx_community_dispatch_stop
where nx_cds_driver_route_id = #{value}
  and nx_cds_stop_status not in ('CANCELLED', 'DELIVERED')

mapper.update:
update nx_community_dispatch_stop
nx_cds_driver_route_id = #{nxCdsDriverRouteId}, nx_cds_stop_status = #{nxCdsStopStatus}, nx_cds_route_seq = #{nxCdsRouteSeq}, nx_cds_delivered_at = #{nxCdsDeliveredAt}, nx_cds_order_count = #{nxCdsOrderCount},
where nx_community_dispatch_stop_id = #{nxCommunityDispatchStopId}
